css:
/* 作者：栗子*/
/* 禁商禁二传 */
/* 可自用二改 */
/* 感谢各位美化老师们的慷慨分享（抹泪）*/
/* 使用过商业美化或支持商业化的人不准用，我觉得特恶心 */
/* 消息元三元素错位请在root里自改 */

@import url("https://fontsapi.zeoseven.com/875/main/result.css");
/* == 全局设置 & 字体== */
:root {
    --topBarBlockSize: 27px; 
    --box-border-radius: 5px;
    --top-distance: 7px;
    --scroll-width: 4px;

/* == 调整消息元三要素位置== */
/*楼层*/
--楼层水平方向:120px; /* 越小越左 */
--楼层垂直方向:185px;  /* 越小越上 */ 

/*消耗*/
--token水平方向:150px; /* 越小越左 */
--token垂直方向:210px;  /* 越小越上 */

/*时间*/
--时间水平方向:190px; /* 越小越左 */
--时间垂直方向:228px;  /* 越小越上 */
}

body,
.text_pole:not(#completion_prompt_manager_list),
select,
textarea:not(#send_textarea),
input {
    font-family: "ChillHuoSong_F";
    font-weight: normal;
}

code,
code * {
    font-family: "ChillHuoSong_F" !important;
    font-weight: normal !important;
}

/* == 聊天主界面布局 == */
/* 二改自kakaa老师的双色盒子 */
#sheld {
    height: calc(100dvh - var(--topBarBlockSize));    
    background-size: cover !important;
}
/*其他背景图*/
#left-nav-panel.drawer-content,
#user-settings-block.drawer-content,
#right-nav-panel.drawer-content,
#rm_extensions_block.drawer-content,
#PersonaManagement.drawer-content{
    background-repeat: no-repeat!important;
    background-size: cover!important;   
}
#left-nav-panel.drawer-content{background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');}
#user-settings-block.drawer-content{background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');}
#rm_extensions_block.drawer-content{background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');}
#PersonaManagement.drawer-content{background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');}
#right-nav-panel.drawer-content{background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');}
#chat {
    background: transparent !important;
    background-color: transparent !important;
    backdrop-filter: none;
    border: none !important;
    overflow-y: scroll;
    align-items: center;
    max-height: calc(100dvh - var(--topBarBlockSize) - 20px) !important;
    margin-left:3px;
    border-radius: 0 0 var(--box-border-radius) var(--box-border-radius);
}

@supports (-webkit-touch-callout: none) {
    #chat {
        padding-right: var(--scroll-width);
    }
}

/*滚动条贴图学习了千尾老师*/
::-webkit-scrollbar {
    width: 4px;
}

::-webkit-scrollbar-track {
    background: transparent!important;
    padding: 0;
   border: none;
}
::-webkit-scrollbar-thumb{
background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
   background-size: 30px 30px;

  background-color: transparent !important;
  background-repeat: no-repeat;
  background-position: center center;
  border: none !important;
  box-shadow: none !important;
  border-radius: 20px;}
::-webkit-scrollbar-thumb:vertical,
::-webkit-scrollbar-thumb:horizontal {
    background-color: #ffffff;
    box-shadow: none;
    border: 0;
}

/* == 消息气泡 == */
.mes {
    width: 100%;
  position: relative;
    min-height:auto; /* 增加最小高度 */
    padding: 8px 10px;
    display: flex;
    flex-direction: column;
    align-items: center; 
    background: linear-gradient(to bottom, rgba(0, 0, 0, 1) 0%, rgba(0, 0, 0, 1) 3%, rgba(0, 0, 0, 0.5) 100%) !important;
    margin:  5.5rem auto ;   

    border-radius: 0px!important;

}
.last_mes {
  margin-bottom: 5.5rem !important;
}


/* 气泡背景装饰 */
.mes::before {
     content: "";
     position: absolute;     
     top: -40px;
     width:120%;
     left:-4px;
     right:0px;
    height:420px;   
     background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
     background-size: 30px 13px;
     background-size: auto 100%;
     background-repeat: repeat-x;
     opacity: 1 !important;
     pointer-events: none; 
}
@media(min-width: 369px) and (max-width:389px)  {
  .mes::before {
    height:435px;   
  }
}
/* ios 小米 */
@media (min-width: 390px) and (max-width:414px) {
  .mes::before {
    height:455px;  
  }
  .mesIDDisplay,
.tokenCounterDisplay,
.mes_timer { 
     --meta-global-offset-x: 15px; 
    --meta-global-offset-y: 25px; 
}
#chat .mes .avatar {

    transform:scale(2.8)!important;

}
}

/* 华为 */
@media (min-width: 415px) and (max-width:440px) {
  .mes::before {
    height:490px;  
  }
.mes_buttons{
margin-top:20px;
}
.mesIDDisplay,
.tokenCounterDisplay,
.mes_timer { 
     --meta-global-offset-x: 35px; 
    --meta-global-offset-y: 50px; 
}
.mes_text {
margin-top:40px!important;
}
#chat .mes .avatar {

    transform:scale(3.2)!important;

}

}
.mes::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: 0;
  width: 100%;    
  height: 180px;

  background-size: auto 100%;
  background-repeat: repeat-x;
  opacity: 0.8 !important;
  pointer-events: none;
  mask: linear-gradient(to bottom, rgba(0,0,0,0), rgba(0,0,0,1) 70%);
  -webkit-mask: linear-gradient(to bottom, rgba(0,0,0,0), rgba(0,0,0,1) 70%);
}
.mes[mesid]:nth-child(3n+1)::after {
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); !important;
}

.mes[mesid]:nth-child(3n+2)::after {
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); !important;
}

.mes[mesid]:nth-child(3n+3)::after {
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); !important;
}

/* ==头像与名字 == */
.mesAvatarWrapper {
    position: relative;    
    top:50px;
    right:22%;
    transform: none !important;
    padding: 3px !important;    
    margin-bottom: 200px;
 }

 #chat .mes .avatar {

    position: absolute;
    display: inline-block;
    padding: 8px;
    top:-30px;
    left:-30px;
    opacity: 1!important;
    transform:scale(2.6);

}

#chat .mes .avatar img {
    border-radius: 0%;
    position:absolute;
    width:100px;
    height:100px;
    object-fit: cover;
    object-position:auto 0%;
    z-index:1;

    box-shadow: none !important; 
    -webkit-mask: url(data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=) center / 100% 100% no-repeat;
    mask: url(data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=) center / 100% 100% no-repeat;
}




#quickPersona{
position:absolute;
left:1px;
opacity:1!important;
}

/* 头像选中框 */
.avatar-container.interactable.selected {
    background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') no-repeat center center !important;
    background-size: cover !important; 
}




/* ==消息内容与排版== */

.mes_block {
    width: 100%;
    padding-left: 0;
    padding-right: 0;
    z-index:999;
    position:relative;
    padding-top: 100px;
    padding-bottom: 70px;
}
/* 名字栏 */
.ch_name.flex-container.justifySpaceBetween{
    position: relative;

   z-index:999;
}
.mes .name_text {
     font-size: 17px;
     font-weight: 600;
     color: #f2ebd9;
     position: absolute;
     top: -95px; 
     left: 60px;  
     display: block;
     transform-origin: center;
     text-align: left; 
     z-index: 9;
     transform: none!important;
     opacity: 1!important;
     writing-mode: vertical-rl;
     text-orientation: upright;
     height: auto;  
     min-height: 60px; 
     max-height: 80px;
     white-space: normal;
     word-break: break-all;
     box-sizing: border-box; 
     margin: 0; 
     width: auto; 
 }
.mes .name_text::before {
    content: "";
    position: absolute;
    top: -15px;
    left: -15px;
    width: calc(150% + 32px);
    height: calc(150%);
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
    background-size: contain;
    background-repeat: no-repeat;
    z-index: -1;
    pointer-events: none;
    opacity:0.9;
}
.mes .timestamp {
    font-size: 15px;
    font-weight: 600;
    color: #c9c8b4;
    position: absolute;
    left:0px;
    top:-12px ;
    display: flex;
    transform-origin: center;
    transform:none!important;
    text-align: center;
   opacity:1!important;
    z-index:99;
}
.mes .timestamp::before {

  content: "";
    position: absolute;
    top: -90px;
    left:-25px;
    width: calc(800% + 100px);
    height: calc(800%);
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
    background-size: contain;
    background-repeat: no-repeat;
    z-index: 9999;
    pointer-events: none;
    opacity:1;
}
.mes .timestamp::after { 
   content: "⁺𓆩⁺₊ ✞𝕾𝖔𝖕𝖍𝖎𝖆 𝖔𝖓 𝖙𝖊𝖍 𝖊𝖘𝖙𝖆𝖙𝖊⋆ ₊⁺𓆪⁺";
   position: absolute;
   left: 75%; 
   transform: translateX(-50%);
   top: 100%; 
   margin-top: 2px; 
   white-space: nowrap; 
   z-index: 999; 
}

/*操作按钮*/
.mes_buttons{
position:absolute;
top: 25px; 
left: 0;
z-index:999;
width:100%;

}

/* 编辑按钮图标替换 */
.mes_button.mes_edit.fa-pencil.interactable {
    position: relative;

    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0; 
    color: transparent;
    border: none;
    background: transparent;
    cursor: pointer;
    z-index: 99;
    width: 30px;
    height: 30px;
    opacity:1!important;
}

.mes_button.mes_edit.fa-pencil.interactable::after {
    content: '' !important;
    position: absolute; 

    width: 100%;
    height: 100%;
    background-size: contain;
    background-position: center;
    background-repeat: no-repeat;
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
    font-size: 0;
    box-shadow: none !important;
}
/*编辑菜单位置调整  */
/*二改自易碎蝶老师*/
.mes_edit_buttons {
    position: absolute;
     top: 28px !important;   
    right:5px !important;   
    opacity: 0 !important;
    pointer-events: none !important;
    transition: opacity 0.2s !important;
   transform: scale(0.95);
}

.mes:hover .mes_edit_buttons,
.mes.selected .mes_edit_buttons {
    opacity: 1 !important;
    pointer-events: auto !important;
}
.mes_button, .extraMesButtons>div {
cursor: pointer;
    transition: opacity 0.2s ease-in-out;
    filter: drop-shadow(0px 0px 0px #ffffff) !important;

opacity: 1 !important;

}
/* 消息操作按钮图标替换 */
.mes_button.extraMesButtonsHint.fa-ellipsis.interactable {
    position: relative;

    width: 30px;
    height: 30px; 
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0; 
    color: transparent;
    border: none;
    background: transparent;
    cursor: pointer;
    z-index: 9999;
}
.mes_button.extraMesButtonsHint.fa-ellipsis.interactable::after {
    content: '' !important;
    position: absolute; 
    width: 100%;
    height: 100%;
    background-size: contain;
    background-position: center;
    background-repeat: no-repeat;
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
    font-size: 0;
    box-shadow: none !important;
}

.mes_button.favorite-toggle-icon.interactable {
    position: relative;
    margin-right:15px; 
    width: 20px;
    height: 20px;
    color: #7BC7D2 !important;
    opacity:1!important; 
}

/* 源自12老师 */
.mes_text br:first-child{
    display: none !important;
}

.mes_text {
    width:100%;
    padding: 15px 0px 20px 4px !important;
    margin-top:25px;
    z-index: 999;
   flex: 1;
}
.mes_text p {
    margin-bottom: 1em!important;
    line-height: 1.5;
}

q {
    background-color: rgba(255,255,255,0.8) !important; 
    padding: 2px 4px !important; 
     margin:4px 4px!important;
    border-radius: 5px !important;      
}
/* 代码块样式 */
.mes_text code {
    display: inline-block;
    background-color: #1a1a1a !important; /* 哥特黑灰底 */
    padding: 8px 8px;
    margin: 5px 8px 5px 0 !important;
    color: #f8f8f8 !important; /* 哑光白文字 */
    border: 0.9px solid #f2b0b0 !important; /* 浅红细边框 点缀哥特调 */
    border-radius: 4px !important;
    letter-spacing: 0.3px !important;
    word-spacing: 1px !important;
    line-height: 1.4 !important;
    font-size: 1em !important;
    box-shadow: 0 0 6px rgba(0, 0, 0, 0.6) !important;
}
.mes_text blockquote {   
    margin: 16px 8px 20px 0 !important;
    padding: 20px 24px !important;  
    position: relative;

}

.mes_text blockquote::before {
    content: "";
    position: absolute;
    display: inline-block;
    width: 70px;
    height: 70px;
    right: 0;
    bottom: 0;
    background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');
    background-size: contain;
    background-repeat: no-repeat;
    opacity: 0.6;
}

/*思维链 */
.mes_reasoning_header {
    position: relative !important;
    top: 32px !important;
    left: 8px !important;
     transform: none !important;
    transition: none !important;
    animation: none !important;
    width: 90% !important;
    height: 10px !important;
    color: transparent !important;
    font-size: 1em !important;
    background-color:rgba(225,225,225,0) !important;
    background-image: none !important;
    background-size: cover !important;
    background-position: center center !important;

}

.mes_reasoning_header.flex-container::before {
    content: "⁺✞✟₊˚₊‧꒰ა ♱ ໒꒱ ‧₊˚⁺✞✟₊";
    position: absolute !important;
    top: 50% !important;
    left: 50% !important;
    transform: translate(-50%, -50%) !important;
    color: #fff !important;
    font-size: 1em !important;
    font-weight: 600 !important;
    letter-spacing: 1px !important;
    text-transform: uppercase !important;
    white-space: nowrap !important;
    z-index: 2 !important;
}
.mes_reasoning{
position:relative;
top:20px;}
/* ==消息元数据 == */
/* 定义统一偏移变量 */

.mesIDDisplay,
.tokenCounterDisplay,
.mes_timer {

    position: absolute !important;
    display: inline-block;
    transform-origin: left top;
    opacity: 0.5 !important;
    font-style: oblique !important;
    color: #000;
    font-size: 16px !important;
    font-weight: 500;
    text-align: right;
}


.mesIDDisplay { 
    left: calc(var(--楼层水平方向) + var(--meta-global-offset-x, 0px));
    top: calc(var(--楼层垂直方向) + var(--meta-global-offset-y, 0px));
    transform: rotate(-10deg) !important;
}

.tokenCounterDisplay { 
    left: calc(var(--token水平方向) + var(--meta-global-offset-x, 0px));
    top: calc(var(--token垂直方向) + var(--meta-global-offset-y, 0px));
    transform: rotate(-12deg) !important;
}

.mes_timer { 
    left: calc(var(--时间水平方向) + var(--meta-global-offset-x, 0px));
    top: calc(var(--时间垂直方向) + var(--meta-global-offset-y, 0px));
    transform: rotate(-14deg) !important;
}

.mesIDDisplay:empty,
.tokenCounterDisplay:empty,
.mes_timer:empty {
    display: none !important;
}


.margin0 {
    font-size: 13px !important;
    font-weight: 600;
}


.swipe_left.fa-solid.fa-chevron-left.interactable::before,
.swipe_right.fa-solid.fa-chevron-right.interactable::before {
    content: "" !important; 
    font-family: initial !important; 
    font-size: 0 !important; 
    display: inline-block;   
    background-position: center;
    background-repeat: no-repeat;
    background-size: contain;    
    transform-origin: center;
    vertical-align: middle;
    overflow: visible; 
}


.swipe_right.fa-solid.fa-chevron-right.interactable {    
    transform: translateX(30px);
    opacity: 1 !important; 
}

.swipe_right.fa-solid.fa-chevron-right.interactable::before{
    position:absolute;
    width: 50px; 
    height: 50px;
    top:-20px;
    left:-50px;
}


.swipe_left.fa-solid.fa-chevron-right.interactable::before{
    position:absolute;
    width: 50px; 
    height: 50px;
    top:-20px;
    left:-50px;

}

.swipes-counter {
  position: absolute;
  top: 50px;
  right: 35%;
  font-size: 10px!important; 
  font-family:"ChillHuoSong_F";
  opacity: 1 !important;
  color: #504e4f !important;
  white-space: nowrap !important;
  z-index: 99;
  position: relative; 
  display: inline-flex; 
  align-items: center;  
  transform:scale(2);
}
/* 前缀文字样式 */
.swipes-counter::before {
    content: "⁺✞✟₊";
    color: #504e4f;

    margin-right: 10px;
    font-family: inherit; /* 新增：继承主字体，保证基线一致 */
}
/* 后缀文字样式 */
.swipes-counter::after {
    content: "⁺✞✟₊";
    color: #504e4f;

    margin-left: 10px;
    font-family: inherit; 
}

.swipes-counter:empty {
     display: none;
 }



/* ==顶部栏== */
#top-bar {
    background-color: rgba(255, 254, 248, 0);
    background-position: center;
    background-repeat: no-repeat;
    box-shadow: none;  
    position: relative;
    height: 30px;
    width: 100%;  
   background: transparent !important;
  background-color: transparent !important;
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
  box-shadow: none !important;
  border: none !important; 
}
#top-bar::after {
content: "";
   position: absolute; 
   top: -100%!important;
   left: 0;
   width: 100%;
   height: 112px; 
   background: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=') top center repeat-x;
   background-size: auto 100%; 
   pointer-events: none;
   z-index: -1;
   opacity:!important;
}
#top-settings-holder{
position:relative;
top:-30px;}

/* 顶部图标通用样式 */
#top-settings-holder .drawer-icon::before {
    content: '' !important;
    display: block;
    opacity:1!important;
    background-size: contain;
    background-position: center;
    background-repeat: no-repeat;
    transition: all 0.3s ease-in-out;
    width: 25px;
    height: 25px;  
}

#top-settings-holder .drawer-icon:active::before {
    transform: translateY(-5px);
}
#extensions-settings-button .drawer-icon::before{
   position:relative;
   left:4px;}
/* 各个按钮图标替换 */
#leftNavDrawerIcon::before,
#sys-settings-button .drawer-icon::before,
#advanced-formatting-button .drawer-icon::before,
#WI-SP-button .drawer-icon::before,
#user-settings-button .drawer-icon::before,
