/* 滑块 (Range Input) */
input[type="range"],
input[type="range"]:disabled {
    -webkit-appearance: none!important;
    filter: none!important;
    box-shadow: none!important;    
background: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") repeat-x center center !important;
